import{_ as o,c as t,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新ログ：バージョン履歴 | opencode-md-table-formatter","description":"opencode-md-table-formatter のバージョン進化と新機能を理解します。v0.1.0 の機能（自動フォーマット、幅キャッシュなど）を確認できます。","frontmatter":{"title":"更新ログ：バージョン履歴 | opencode-md-table-formatter","sidebarTitle":"バージョン変更一覧","subtitle":"更新ログ：バージョン履歴と変更記録","description":"opencode-md-table-formatter のバージョン進化と新機能を理解します。v0.1.0 の機能（自動フォーマット、幅キャッシュなど）を確認できます。","tags":["changelog","version-history","release-notes"],"prerequisite":[],"order":90},"headers":[],"relativePath":"ja/franlol/opencode-md-table-formatter/changelog/release-notes/index.md","filePath":"ja/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"}'),a={name:"ja/franlol/opencode-md-table-formatter/changelog/release-notes/index.md"};function i(n,e,s,d,c,g){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="更新ログ-バージョン履歴と変更記録" tabindex="-1">更新ログ：バージョン履歴と変更記録 <a class="header-anchor" href="#更新ログ-バージョン履歴と変更記録" aria-label="Permalink to &quot;更新ログ：バージョン履歴と変更記録&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">学習後の成果</p><ul><li>プラグインのバージョン進化の過程を追跡できる</li><li>各バージョンの新機能と修正を理解できる</li><li>既知の制限事項と技術的な詳細を把握できる</li><li>将来の機能強化の可能性を理解できる</li></ul></div><hr><h2 id="_0-1-0-2025-01-07" tabindex="-1">[0.1.0] - 2025-01-07 <a class="header-anchor" href="#_0-1-0-2025-01-07" aria-label="Permalink to &quot;[0.1.0] - 2025-01-07&quot;">​</a></h2><h3 id="新機能" tabindex="-1">新機能 <a class="header-anchor" href="#新機能" aria-label="Permalink to &quot;新機能&quot;">​</a></h3><p>これは opencode-md-table-formatter の<strong>初期リリースバージョン</strong>で、以下のコア機能が含まれています：</p><ul><li><strong>自動テーブルフォーマット</strong>：<code>experimental.text.complete</code> フックを使用して、AI が生成した Markdown テーブルを自動的にフォーマット</li><li><strong>非表示モード対応</strong>：幅計算時に非表示の Markdown 記号（<code>**</code>、<code>*</code> など）を正しく処理</li><li><strong>ネストされた Markdown 処理</strong>：任意の深さのネストされた Markdown 構文をサポートし、多段階のストリップアルゴリズムを使用</li><li><strong>コードブロック保護</strong>：インラインコード（<code>`code`</code>）内の Markdown 記号はリテラル形式で保持され、幅計算には参加しない</li><li><strong>配置方式対応</strong>：左揃え（<code>---</code> または <code>:---</code>）、中央揃え（<code>:---:</code>）、右揃え（<code>---:</code>）をサポート</li><li><strong>幅キャッシュ最適化</strong>：文字列表示幅の計算結果をキャッシュしてパフォーマンスを向上</li><li><strong>無効なテーブル検証</strong>：テーブル構造を自動的に検証し、無効なテーブルにはエラーコメントを追加</li><li><strong>複数文字対応</strong>：Emoji、Unicode 文字、空セル、超長コンテンツをサポート</li><li><strong>静的エラー処理</strong>：フォーマット失敗時でも OpenCode ワークフローを中断しない</li></ul><h3 id="技術詳細" tabindex="-1">技術詳細 <a class="header-anchor" href="#技術詳細" aria-label="Permalink to &quot;技術詳細&quot;">​</a></h3><p>このバージョンには約 <strong>230 行の本番対応 TypeScript コード</strong>が含まれています：</p><ul><li><strong>12 の関数</strong>：責任が明確で、適切に分離されている</li><li><strong>タイプセーフ</strong>：<code>Hooks</code> インターフェースを正しく使用</li><li><strong>スマートキャッシュクリア</strong>：操作数が 100 回を超えるか、キャッシュエントリが 1000 を超えるとクリアがトリガーされる</li><li><strong>多段階正規表現処理</strong>：任意のネスト深さの Markdown 記号ストリップをサポート</li></ul><div class="tip custom-block"><p class="custom-block-title">キャッシュメカニズム</p><p>キャッシュは繰り返しコンテンツの幅計算を最適化するために設計されています。例えば、テーブル内で同じセルテキストが複数回出現する場合、幅は一度だけ計算され、その後はキャッシュから直接読み取られます。</p></div><h3 id="既知の制限事項" tabindex="-1">既知の制限事項 <a class="header-anchor" href="#既知の制限事項" aria-label="Permalink to &quot;既知の制限事項&quot;">​</a></h3><p>このバージョンは以下のシナリオをサポートしていません：</p><ul><li><strong>HTML テーブル</strong>：Markdown パイプテーブル（Pipe Table）のみをサポート</li><li><strong>複数行セル</strong>：<code>&lt;br&gt;</code> タグを含むセルはサポートされていない</li><li><strong>区切り行なしテーブル</strong>：テーブルをフォーマットするには区切り行（<code>|---|</code>）が必要</li><li><strong>依存関係要件</strong>：<code>@opencode-ai/plugin</code> &gt;= 0.13.7 が必要（公開されていない <code>experimental.text.complete</code> フックを使用）</li></ul><div class="info custom-block"><p class="custom-block-title">バージョン要件</p><p>プラグインは OpenCode &gt;= 1.0.137 と <code>@opencode-ai/plugin</code> &gt;= 0.13.7 に依存して正常に動作します。</p></div><hr><h2 id="今後の計画" tabindex="-1">今後の計画 <a class="header-anchor" href="#今後の計画" aria-label="Permalink to &quot;今後の計画&quot;">​</a></h2><p>以下の機能は将来のバージョンで実装される予定です：</p><ul><li><strong>設定オプション</strong>：最小/最大列幅のカスタマイズ、特定機能の無効化をサポート</li><li><strong>ヘッダーなしテーブル対応</strong>：ヘッダー行のないテーブルをフォーマット</li><li><strong>パフォーマンス最適化</strong>：超大規模テーブル（100 行以上）のパフォーマンス分析と最適化</li><li><strong>より多くの配置オプション</strong>：配置方式の構文と機能を拡張</li></ul><div class="tip custom-block"><p class="custom-block-title">コントリビューション</p><p>機能提案やコード貢献をお考えの場合は、<a href="https://github.com/franlol/opencode-md-table-formatter/issues" target="_blank" rel="noreferrer">GitHub Issues</a> でアイデアを共有してください。</p></div><hr><h2 id="変更記録フォーマットの説明" tabindex="-1">変更記録フォーマットの説明 <a class="header-anchor" href="#変更記録フォーマットの説明" aria-label="Permalink to &quot;変更記録フォーマットの説明&quot;">​</a></h2><p>このプロジェクトの更新ログは <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> フォーマットに従い、バージョン番号は <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">セマンティックバージョニング (Semantic Versioning)</a> に従います。</p><p><strong>バージョン番号フォーマット</strong>：<code>MAJOR.MINOR.PATCH</code></p><ul><li><strong>MAJOR</strong>：互換性のない API 変更</li><li><strong>MINOR</strong>：後方互換性のある新機能</li><li><strong>PATCH</strong>：後方互換性のある問題修正</li></ul><p><strong>変更タイプ</strong>：</p><ul><li><strong>Added</strong>：新機能</li><li><strong>Changed</strong>：既存機能の変更</li><li><strong>Deprecated</strong>：削除予定の機能</li><li><strong>Removed</strong>：削除された機能</li><li><strong>Fixed</strong>：問題修正</li><li><strong>Security</strong>：セキュリティ関連の修正</li></ul><hr><h2 id="推奨学習順序" tabindex="-1">推奨学習順序 <a class="header-anchor" href="#推奨学習順序" aria-label="Permalink to &quot;推奨学習順序&quot;">​</a></h2><p>新規ユーザーの場合、以下の順序で学習することをお勧めします：</p><ol><li><a href="./../../start/getting-started/">1分で始める：インストールと設定</a> —— クイックスタート</li><li><a href="./../../start/features/">機能概要：自動フォーマットの魔法</a> —— コア機能を理解</li><li><a href="./../../faq/troubleshooting/">よくある質問：テーブルがフォーマットされない場合</a> —— トラブルシューティング</li><li><a href="./../../appendix/limitations/">既知の制限事項：プラグインの境界</a> —— 制限事項を理解</li></ol>',31)])])}const m=o(a,[["render",i]]);export{h as __pageData,m as default};
